-- ============================================================================
-- LESSON: lesson-t-overview
-- Images: page2_img1 -> "Industry Alignment" section
-- ============================================================================
UPDATE lessons SET content_json = json_set(
  json_remove(content_json, '$.images'),
  '$.sections',
  json('[
    {"title":"Introduction","content":"In this program you will design and implement a fully functioning smartwatch by combining low level driver development, embedded systems programming, and system-level integration.\n\nYou will work on the **LilyGo T-Watch 2020 V3**, a real commercial smartwatch platform, and write production-style firmware entirely in C and C++: the same languages used in industry for resource-constrained embedded systems.\n\n- **C** is used for low-level hardware control and communication\n- **C++** enables modular design, abstraction, and higher-level application logic\n\nThroughout the program you will build your system incrementally using provided training materials, reference implementations, and targeted code examples. These resources are designed to support you without removing the need for engineering decision making.\n\nIf you need help, email **support@shortcct.com** with your specific questions and a zip file including your project directory. Remember, virtual support is available for **3 months** after your product delivery date."},
    {"title":"Recommended Background","content":"This project is designed for students who want hands-on embedded firmware experience. You do not need a lot of experience, but some foundational knowledge is expected.\n\n**Required:**\n- Introductory programming experience in C or C++\n- Comfort with basic programming concepts such as functions, control flow, arrays, and structs\n\n**Helpful:**\n- Introductory exposure to embedded systems\n- Introductory electronics knowledge\n\nIf you find that you are missing some of this background, reach out to us at **support@shortcct.com** and we can explore options to get you up to speed!"},
    {"title":"Industry Alignment","content":"We analyzed the most in-demand skills across 50+ companies hiring embedded systems engineering interns. Below is how the Smartwatch Project aligns with those skills.\n\n**Core Skills** are fully covered in the base project.\n**Extendable Skills** can be developed through optional project extensions and the design challenge.\n**Not Covered** indicates skills that are outside the scope of the core project.","images":[{"url":"https://www.genspark.ai/api/files/s/2D27gI2m","alt":"Industry Alignment Skills Table","caption":"How the Smartwatch Project aligns with in-demand embedded systems skills"}]},
    {"title":"Documentation","content":"Here is the relevant documentation that you will need to use throughout the development of your project:\n\n**Datasheets:**\n- [AXP202 Datasheet](https://linux-sunxi.org/images/2/20/AXP202_Datasheet_v1.0_en.pdf) - Power Management IC\n- [PCF8563 Datasheet](https://www.nxp.com/docs/en/data-sheet/PCF8563.pdf) - Real-Time Clock\n- [ST7789V Datasheet](https://www.displayfuture.com/Display/datasheet/controller/ST7789V.pdf) - Display Controller\n- [FT6236U Datasheet](https://www.buydisplay.com/download/ic/FT6236-FT6336-FT6436L-FT6436_Datasheet.pdf) - Touch Controller\n- [BMA423 Datasheet](https://www.mouser.com/datasheet/2/783/BSCH_S_A0010021471_1-2525113.pdf) - Accelerometer\n\n**Libraries:**\n- [TFT_eSPI Library](https://doc-tft-espi.readthedocs.io/) - Display Graphics Library\n- [AXP202X_Library](https://github.com/lewisxhe/AXP202X_Library) - Power Management Library\n- [BMA423_Library](https://github.com/lewisxhe/BMA423_Library/tree/master) - Accelerometer Library\n\n**Other:**\n- [T-Watch Pinout](https://github.com/Xinyuan-LilyGO/TTGO_TWatch_Library/blob/master/docs/watch_2020_v3.md)\n- [T-Watch Schematic](https://github.com/Xinyuan-LilyGO/TTGO_TWatch_Library/blob/master/Schematic/T_WATCH-2020V03.pdf)"},
    {"title":"Set Up Smartwatch","content":"To set up PlatformIO, this video by DroneBot Workshop is a great resource. It includes installation steps for Linux, MacOS, and Windows. You can download the latest versions of Python and Visual Studio Code.\n\nOnce you have downloaded PlatformIO on your system, watch the following video to set up your environment for our project.\n\nThe following video shows you how to clone our GitHub repository, [short-circuit-projects/smartwatch](https://github.com/short-circuit-projects/smartwatch), to VSCode. This tutorial is done on Windows, so it will look different on Linux or MacOS."}
  ]')
) WHERE id = 'lesson-t-overview';

-- ============================================================================
-- LESSON: lesson-t-files
-- Images: page5_img1 -> "Header File Example", page5_img2 -> "C Source File", page6_img1 -> "C++ Source File"
-- ============================================================================
UPDATE lessons SET content_json = json_set(
  json_remove(content_json, '$.images'),
  '$.sections',
  json('[
    {"title":"File Structure: Headers and Source Files","content":"A well-structured embedded project separates code into **header files** (.h) and **source files** (.c or .cpp). This organization improves readability, enables code reuse, and supports modular development.\n\n**Header Files (.h)**\n- Contain declarations: function prototypes, macros, type definitions\n- Act as the public interface to a module\n- Include guards prevent multiple inclusion\n\n**Source Files (.c or .cpp)**\n- Contain implementations: function definitions, static variables\n- Include their corresponding header file\n- Hide internal details from other modules"},
    {"title":"Header File Example (accel.h)","content":"Header files declare the public interface. They tell other files what functions and types are available without revealing implementation details.\n\n```c\n#ifndef ACCEL_H\n#define ACCEL_H\n\n#include <stdint.h>\n\n// Public function declarations\nvoid accel_init(void);\nint16_t accel_read_x(void);\nint16_t accel_read_y(void);\nint16_t accel_read_z(void);\n\n#endif // ACCEL_H\n```\n\nThe `#ifndef`, `#define`, and `#endif` are **include guards** that prevent the header from being processed multiple times.","images":[{"url":"https://www.genspark.ai/api/files/s/W6YXjNvj","alt":"Header file example showing accel.h","caption":"Header File (accel.h) - Declares the public interface"}]},
    {"title":"C Source File (accel.c)","content":"C source files implement the functions declared in the header. They contain the actual code that runs on the device.\n\n```c\n#include \"accel.h\"\n#include \"i2c.h\"\n\n#define ACCEL_ADDR 0x18\n\nstatic uint8_t accel_buffer[6];\n\nvoid accel_init(void) {\n    i2c_write_reg(ACCEL_ADDR, 0x20, 0x47);\n}\n\nint16_t accel_read_x(void) {\n    i2c_read_bytes(ACCEL_ADDR, 0x28, accel_buffer, 2);\n    return (int16_t)((accel_buffer[1] << 8) | accel_buffer[0]);\n}\n```\n\nNote that `accel_buffer` is declared `static`, making it private to this file.","images":[{"url":"https://www.genspark.ai/api/files/s/cjAQlIAb","alt":"Source file example showing accel.c","caption":"C Source File (accel.c) - Implements the functionality"}]},
    {"title":"C++ Source File (display.cpp)","content":"C++ source files use classes and object-oriented features. The structure is similar to C but with additional capabilities.\n\n```cpp\n#include \"display.h\"\n#include <TFT_eSPI.h>\n\nstatic TFT_eSPI tft;\n\nvoid display_init(void) {\n    tft.init();\n    tft.setRotation(2);\n    tft.fillScreen(TFT_BLACK);\n}\n\nvoid display_text(const char* text, int x, int y) {\n    tft.setCursor(x, y);\n    tft.print(text);\n}\n\nvoid display_clear(void) {\n    tft.fillScreen(TFT_BLACK);\n}\n```\n\nC++ files use `.cpp` extension and can leverage libraries like TFT_eSPI that provide object-oriented interfaces.","images":[{"url":"https://www.genspark.ai/api/files/s/KrdlcPTc","alt":"C++ source file example showing display.cpp","caption":"C++ Source File (display.cpp) - Uses classes and OOP"}]}
  ]')
) WHERE id = 'lesson-t-files';

