-- LESSON: lesson-t-oop
-- Images mapped to sections:
-- page21_img1 -> "Classes and Objects" (Basic Class Declaration)
-- page21_img2 -> "Classes and Objects" (Creating Multiple Objects)
-- page22_img1 -> "Encapsulation and Access Control"
-- page23_img1 -> "Encapsulation for Hardware"
-- page24_img1 -> "Constructors"
-- page25_img1 -> "Header and Source Files for Classes" (header)
-- page25_img2 -> "Header and Source Files for Classes" (source)
-- page26_img1 -> "Using Classes in Main Code"
-- ============================================================================
UPDATE lessons SET content_json = json_set(
  json_remove(content_json, '$.images'),
  '$.sections',
  json('[
    {"title":"Introduction to OOP in Embedded Systems","content":"Object-Oriented Programming (OOP) in C++ helps organize complex embedded projects. While C is sufficient for many embedded tasks, C++ classes provide:\n\n- **Encapsulation** - Bundle data and functions together\n- **Abstraction** - Hide implementation details\n- **Modularity** - Self-contained, reusable components\n\nThe T-Watch project uses OOP to create clean interfaces for hardware peripherals like motors, LEDs, and sensors."},
    {"title":"Classes and Objects","content":"A class is a blueprint that defines data (member variables) and behavior (member functions). An object is an instance of a class.\n\n```cpp\nclass Motor {\npublic:\n    int speed;\n    \n    void setSpeed(int s) {\n        speed = s;\n    }\n    \n    void stop() {\n        speed = 0;\n    }\n};\n\n// Creating objects\nMotor leftMotor;\nMotor rightMotor;\n\nleftMotor.setSpeed(100);\nrightMotor.setSpeed(50);\n```\n\nEach object has its own copy of member variables but shares the same member functions.","images":[{"url":"https://www.genspark.ai/api/files/s/qR7sTuVw","alt":"Motor class declaration","caption":"Basic Class Declaration"},{"url":"https://www.genspark.ai/api/files/s/xY8zAbCd","alt":"Creating class instances","caption":"Creating Multiple Objects"}]},
    {"title":"Encapsulation and Access Control","content":"Encapsulation hides internal data and provides controlled access through public methods. Use `private` for internal data and `public` for the interface.\n\n```cpp\nclass Motor {\nprivate:\n    int speed;  // Hidden from outside\n    \npublic:\n    void setSpeed(int s) {\n        if (s >= 0 && s <= 255) {  // Validation\n            speed = s;\n        }\n    }\n    \n    int getSpeed() {\n        return speed;\n    }\n};\n```\n\nThis prevents direct access to `speed` and ensures values are always valid.","images":[{"url":"https://www.genspark.ai/api/files/s/eF9gHiJk","alt":"Encapsulation with state variable","caption":"Encapsulation with Setter Method"}]},
    {"title":"Encapsulation for Hardware","content":"OOP is particularly useful for wrapping hardware peripherals. Each class manages its own pins and state.\n\n```cpp\nclass LED {\nprivate:\n    int pin;\n    bool state;\n    \npublic:\n    LED(int p) : pin(p), state(false) {\n        pinMode(pin, OUTPUT);\n    }\n    \n    void on() {\n        digitalWrite(pin, HIGH);\n        state = true;\n    }\n    \n    void off() {\n        digitalWrite(pin, LOW);\n        state = false;\n    }\n    \n    void toggle() {\n        state ? off() : on();\n    }\n};\n\n// Usage\nLED statusLed(13);\nstatusLed.on();\n```","images":[{"url":"https://www.genspark.ai/api/files/s/lM0nOpQr","alt":"LED class example","caption":"Hardware Encapsulation - LED Class"}]},
    {"title":"Constructors","content":"A constructor is a special function that runs when an object is created. Use it to initialize member variables and configure hardware.\n\n```cpp\nclass Sensor {\nprivate:\n    int i2c_addr;\n    uint8_t buffer[6];\n    \npublic:\n    // Constructor with initialization list\n    Sensor(int addr) : i2c_addr(addr) {\n        // Initialize hardware\n        Wire.begin();\n        configure();\n    }\n    \n    void configure() {\n        i2c_write_reg(i2c_addr, CONFIG_REG, 0x80);\n    }\n};\n\n// Object created and configured automatically\nSensor accel(0x18);\n```\n\nThe initialization list (`: i2c_addr(addr)`) is the preferred way to initialize members.","images":[{"url":"https://www.genspark.ai/api/files/s/sT1uVwXy","alt":"Sensor class with constructor","caption":"Class with Constructor"}]},
    {"title":"Header and Source Files for Classes","content":"Like C modules, C++ classes should be split into header (.h) and source (.cpp) files.\n\n**motor.h:**\n```cpp\n#ifndef MOTOR_H\n#define MOTOR_H\n\nclass Motor {\nprivate:\n    int pwmPin;\n    int dirPin;\n    int speed;\n    \npublic:\n    Motor(int pwm, int dir);\n    void setSpeed(int s);\n    void stop();\n    int getSpeed();\n};\n\n#endif\n```\n\n**motor.cpp:**\n```cpp\n#include \"motor.h\"\n#include <Arduino.h>\n\nMotor::Motor(int pwm, int dir) : pwmPin(pwm), dirPin(dir), speed(0) {\n    pinMode(pwmPin, OUTPUT);\n    pinMode(dirPin, OUTPUT);\n}\n\nvoid Motor::setSpeed(int s) {\n    speed = constrain(s, -255, 255);\n    digitalWrite(dirPin, speed >= 0 ? HIGH : LOW);\n    analogWrite(pwmPin, abs(speed));\n}\n\nvoid Motor::stop() {\n    setSpeed(0);\n}\n\nint Motor::getSpeed() {\n    return speed;\n}\n```","images":[{"url":"https://www.genspark.ai/api/files/s/zA2bCdEf","alt":"Motor header file","caption":"Motor Class Header (motor.h)"},{"url":"https://www.genspark.ai/api/files/s/gH3iJkLm","alt":"Motor source file","caption":"Motor Class Implementation (motor.cpp)"}]},
    {"title":"Using Classes in Main Code","content":"Include the header file and create objects as needed:\n\n```cpp\n#include \"motor.h\"\n#include \"led.h\"\n#include \"sensor.h\"\n\nMotor leftMotor(5, 6);\nMotor rightMotor(9, 10);\nLED statusLed(13);\nSensor accel(0x18);\n\nvoid setup() {\n    Serial.begin(115200);\n    statusLed.on();\n}\n\nvoid loop() {\n    int16_t x, y, z;\n    accel.read(&x, &y, &z);\n    \n    // Use accelerometer to control motors\n    leftMotor.setSpeed(map(x, -2000, 2000, -255, 255));\n    rightMotor.setSpeed(map(y, -2000, 2000, -255, 255));\n    \n    delay(50);\n}\n```\n\nOOP makes the main code clean and focused on high-level logic rather than low-level details.","images":[{"url":"https://www.genspark.ai/api/files/s/nO4pQrSt","alt":"Using motor class in main","caption":"Using the Motor Class"}]}
  ]')
) WHERE id = 'lesson-t-oop';

