-- LESSON: lesson-t-fsm
-- Images: page38_img1 -> "Implementing an FSM"
-- ============================================================================
UPDATE lessons SET content_json = json_set(
  json_remove(content_json, '$.images'),
  '$.sections',
  json('[
    {"title":"Introduction to Finite State Machines","content":"A Finite State Machine (FSM) is a design pattern that organizes code around discrete states and transitions. FSMs are ideal for:\n\n- Menu navigation\n- Screen management\n- Device modes (idle, active, sleep)\n- Protocol handling\n- User interaction flows\n\nThe T-Watch uses an FSM to manage different screens: home, time, accelerometer, settings, etc."},
    {"title":"FSM Components","content":"Every FSM has three core components:\n\n**States:** The distinct modes your system can be in\n```c\ntypedef enum {\n    STATE_HOME,\n    STATE_TIME,\n    STATE_ACCEL,\n    STATE_SETTINGS,\n    STATE_SLEEP\n} AppState;\n```\n\n**Events:** Inputs that trigger transitions\n```c\ntypedef enum {\n    EVENT_TOUCH,\n    EVENT_BUTTON,\n    EVENT_TIMEOUT,\n    EVENT_WAKE\n} AppEvent;\n```\n\n**Transitions:** Rules for moving between states based on events"},
    {"title":"Implementing an FSM","content":"A switch statement is the simplest FSM implementation:\n\n```c\nAppState currentState = STATE_HOME;\n\nvoid handle_event(AppEvent event) {\n    switch (currentState) {\n        case STATE_HOME:\n            if (event == EVENT_TOUCH) {\n                currentState = STATE_TIME;\n                enter_time_screen();\n            } else if (event == EVENT_TIMEOUT) {\n                currentState = STATE_SLEEP;\n                enter_sleep();\n            }\n            break;\n            \n        case STATE_TIME:\n            if (event == EVENT_TOUCH) {\n                currentState = STATE_ACCEL;\n                enter_accel_screen();\n            } else if (event == EVENT_BUTTON) {\n                currentState = STATE_HOME;\n                enter_home_screen();\n            }\n            break;\n            \n        case STATE_ACCEL:\n            if (event == EVENT_TOUCH) {\n                currentState = STATE_SETTINGS;\n                enter_settings_screen();\n            }\n            break;\n            \n        // ... more states\n    }\n}\n```\n\nEach state handles its own transitions, making the logic clear and maintainable.","images":[{"url":"https://www.genspark.ai/api/files/s/hI8jKlMn","alt":"FSM implementation with switch statement","caption":"FSM Implementation for Screen Navigation"}]},
    {"title":"Benefits of FSM Design","content":"FSMs provide several advantages:\n\n**Clarity:** The system is always in exactly one known state\n**Debugging:** Easy to trace what state caused a bug\n**Extensibility:** Add new states without breaking existing ones\n**Testing:** Test each state and transition independently\n\nFor complex systems, consider using a state table or state pattern instead of a switch statement."},
    {"title":"State Transitions","content":"Good FSM design includes entry and exit actions:\n\n```c\nvoid transition_to(AppState newState) {\n    // Exit current state\n    switch (currentState) {\n        case STATE_HOME:\n            save_home_position();\n            break;\n        case STATE_TIME:\n            stop_time_update();\n            break;\n    }\n    \n    // Enter new state\n    currentState = newState;\n    switch (newState) {\n        case STATE_HOME:\n            draw_home_screen();\n            start_idle_timer();\n            break;\n        case STATE_TIME:\n            draw_time_screen();\n            start_time_update();\n            break;\n    }\n}\n```\n\nThis ensures resources are properly initialized and cleaned up during transitions."}
  ]')
) WHERE id = 'lesson-t-fsm';

-- ============================================================================
-- LESSON: lesson-t-networking
-- Images mapped to sections:
-- page39_img1 -> "Connecting to WiFi"
-- page40_img1 -> "NTP Time Synchronization"
-- ============================================================================
UPDATE lessons SET content_json = json_set(
  json_remove(content_json, '$.images'),
  '$.sections',
  json('[
    {"title":"Introduction to WiFi on ESP32","content":"The ESP32 has built-in WiFi capabilities that enable:\n\n- **NTP time synchronization** - Get accurate time from the internet\n- **Cloud data upload** - Send sensor data to servers\n- **Notifications** - Receive alerts and messages\n- **OTA updates** - Update firmware wirelessly\n\nThe T-Watch uses WiFi primarily for time synchronization with NTP servers."},
    {"title":"Connecting to WiFi","content":"Use the WiFi library to connect to a network:\n\n```cpp\n#include <WiFi.h>\n\nconst char* ssid = \"YourNetworkName\";\nconst char* password = \"YourPassword\";\n\nvoid wifi_connect() {\n    WiFi.begin(ssid, password);\n    \n    Serial.print(\"Connecting to WiFi\");\n    while (WiFi.status() != WL_CONNECTED) {\n        delay(500);\n        Serial.print(\".\");\n    }\n    \n    Serial.println();\n    Serial.print(\"Connected! IP: \");\n    Serial.println(WiFi.localIP());\n}\n```\n\nAlways include a timeout to avoid hanging if the network is unavailable.","images":[{"url":"https://www.genspark.ai/api/files/s/52YAFb3q","alt":"WiFi connection code","caption":"Basic WiFi Connection"}]},
    {"title":"WiFi Status Checking","content":"Check WiFi status before making network requests:\n\n```cpp\nif (WiFi.status() == WL_CONNECTED) {\n    // Safe to make network requests\n    sync_time();\n} else {\n    Serial.println(\"WiFi not connected\");\n}\n```\n\n**WiFi status constants:**\n- `WL_CONNECTED` - Successfully connected\n- `WL_DISCONNECTED` - Not connected\n- `WL_CONNECT_FAILED` - Connection attempt failed\n- `WL_NO_SSID_AVAIL` - Network not found"},
    {"title":"NTP Time Synchronization","content":"Network Time Protocol (NTP) provides accurate time from internet servers:\n\n```cpp\n#include <time.h>\n\nvoid sync_ntp_time() {\n    configTime(0, 0, \"pool.ntp.org\", \"time.nist.gov\");\n    \n    Serial.print(\"Waiting for NTP sync\");\n    time_t now = time(nullptr);\n    while (now < 1000000000) {\n        delay(500);\n        Serial.print(\".\");\n        now = time(nullptr);\n    }\n    Serial.println(\" Done!\");\n    \n    // Store in hardware RTC\n    struct tm timeinfo;\n    localtime_r(&now, &timeinfo);\n    rtc_set_time(timeinfo.tm_hour, timeinfo.tm_min, timeinfo.tm_sec);\n    rtc_set_date(timeinfo.tm_year + 1900, timeinfo.tm_mon + 1, timeinfo.tm_mday);\n}\n```\n\nAfter NTP sync, store the time in the hardware RTC so it persists without WiFi.","images":[{"url":"https://www.genspark.ai/api/files/s/S6mWhW98","alt":"NTP time sync example","caption":"NTP Time Synchronization"}]},
    {"title":"Power Considerations","content":"WiFi consumes significant power. For a battery-powered watch:\n\n**Best practices:**\n- Only enable WiFi when needed\n- Disconnect and turn off WiFi after use\n- Use periodic sync (once per day) rather than continuous connection\n- Consider light-sleep between operations\n\n```cpp\nvoid wifi_off() {\n    WiFi.disconnect(true);\n    WiFi.mode(WIFI_OFF);\n}\n\nvoid daily_sync() {\n    wifi_connect();\n    sync_ntp_time();\n    wifi_off();  // Save power\n}\n```\n\nWith proper power management, battery life can be significantly extended."}
  ]')
) WHERE id = 'lesson-t-networking';
